import{_ as e,o,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"concepts.md","filePath":"concepts.md"}'),n={name:"concepts.md"};function d(s,t,i,c,l,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h1><h2 id="sifts" tabindex="-1">Sifts <a class="header-anchor" href="#sifts" aria-label="Permalink to &quot;Sifts&quot;">​</a></h2><p>A <strong>Sift</strong> is the core entity in Sifter. It defines:</p><ul><li>A <strong>name</strong> and optional description</li><li><strong>Instructions</strong> — plain English description of what to extract (e.g. <code>&quot;Extract: client name, invoice date, total amount, VAT number&quot;</code>)</li><li>A <strong>schema</strong> — automatically inferred from the first processed document</li><li>A persistent <strong>database of results</strong> (one record per document)</li></ul><p>Sifts have a lifecycle status: <code>active</code>, <code>indexing</code>, <code>paused</code>, <code>error</code>.</p><p>A sift can receive documents in two ways:</p><ul><li><strong>Direct upload</strong> via <code>POST /api/sifts/{id}/upload</code> or <code>sift.upload()</code></li><li><strong>Via Folders</strong> — link a folder and all documents in it are automatically processed</li></ul><h2 id="folders" tabindex="-1">Folders <a class="header-anchor" href="#folders" aria-label="Permalink to &quot;Folders&quot;">​</a></h2><p>A <strong>Folder</strong> is a document container. It connects to one or more sifts (many-to-many):</p><ul><li>Upload a document once — every linked sift processes it automatically</li><li>A sift can be linked to multiple folders</li><li>Folders support renaming and per-document status tracking</li></ul><h2 id="documents" tabindex="-1">Documents <a class="header-anchor" href="#documents" aria-label="Permalink to &quot;Documents&quot;">​</a></h2><p>A <strong>Document</strong> is a file stored in Sifter. Each <code>(document, sift)</code> pair has an independent processing status:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>pending</code></td><td>Queued, not yet started</td></tr><tr><td><code>processing</code></td><td>Worker currently running</td></tr><tr><td><code>done</code></td><td>Extraction complete</td></tr><tr><td><code>error</code></td><td>Extraction failed</td></tr></tbody></table><h2 id="aggregations" tabindex="-1">Aggregations <a class="header-anchor" href="#aggregations" aria-label="Permalink to &quot;Aggregations&quot;">​</a></h2><p><strong>Aggregations</strong> are named, reusable MongoDB aggregation pipelines generated from natural language queries. They are attached to a sift and can be refreshed on demand.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><p>Sifter emits events during processing:</p><table tabindex="0"><thead><tr><th>Event</th><th>When</th></tr></thead><tbody><tr><td><code>sift.document.processed</code></td><td>A document was extracted by a sift</td></tr><tr><td><code>sift.completed</code></td><td>All documents in a sift finished</td></tr><tr><td><code>sift.error</code></td><td>Extraction error on a document</td></tr><tr><td><code>folder.document.uploaded</code></td><td>New document added to a folder</td></tr></tbody></table><p>Events can be consumed via <strong>SDK callbacks</strong> (client-side polling during <code>wait()</code>) or <strong>server-side webhooks</strong>.</p>',19)])])}const h=e(n,[["render",d]]);export{g as __pageData,h as default};
